+    let err: &dyn std::error::Error = &denied;
+    let display = err.to_string();
+    assert!(display.contains("fs_write"));
+    assert!(display.contains("RemoteCaps"));
+    assert!(display.contains("fs-writer"));
+    assert!(err.source().is_none());
